sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {

	// DFCT0010708
	//create a task link using form preferences and the current sys_id
	// TODO, NEED TO TAKE STYLING OUT OF HERE!
	var task_link = new x_153465_discovert.tasker_User_Form_Preferences().getEmailLink(current);

	//create link for email template
	template.print(task_link);

})(current, template, email, email_action, event);
